/**
 * Per-agent sprite customization map.
 *
 * Maps each of the 26 Township agents to a Smallville body sprite plus:
 *
 *  - `customKey`  — a baked palette-swap sheet (generated by
 *    `scripts/mapgen/outfits.py` into `assets/characters/custom/`) that
 *    recolors the garment cluster only, replacing the old whole-body tint.
 *    When the texture is present it wins; `tint` remains as the runtime
 *    fallback for sheets the generator judged unreliable.
 *  - `accessoryKey` — a real pixel overlay spritesheet (generated by
 *    `scripts/mapgen/accessories.py` into `assets/characters/accessories/`),
 *    frame-aligned to the base sheet's head pixels, played frame-locked with
 *    the body (kippah / hijab / cap / hardhat / glasses).
 *  - `partner` — couple agents ("A & B" personas) render a REAL second body
 *    (its own spritesheet) that trails the lead by ~12px with a delayed
 *    follow and an offset walk phase. Partner bodies reuse sheets from other
 *    towns or the split folk sheets so the pair never twins visually.
 *
 * NOTE: the original Adam_Smith and Wolfgang_Schulz Smallville sheets are
 * cats-in-costume, not people — the rabbi and Tom Kowalski now map to human
 * bodies from the split `32x32folk.png` (folk-3 / folk-0).
 */

export interface SpriteCustomization {
  /** Phaser texture key of the base body (e.g., "char-Carlos_Gomez"). */
  spriteKey: string;
  /**
   * Baked palette-swap sheet key (e.g. "char-custom-miguel-hernandez" →
   * assets/characters/custom/miguel-hernandez_custom.png). Preferred over
   * `tint` when the texture loaded.
   */
  customKey?: string;
  /** Runtime multiplicative tint — fallback when no customKey sheet exists. */
  tint?: number;
  /** Accessory overlay key (e.g. "acc-hijab-Abigail_Chen"). */
  accessoryKey?: string;
  /** Couple partner: a real second body that trails the lead sprite. */
  partner?: {
    name: string;
    /** Partner body texture key. Falls back to the lead body + tint. */
    spriteKey?: string;
    tint?: number;
  };
}

