/* ── Fallback ring (rotated when an agent isn't in the table) ── */

export const FALLBACK_SPRITES = [
  "char-Carlos_Gomez",
  "char-Maria_Lopez",
  "char-folk-3",
  "char-Abigail_Chen",
  "char-Tom_Moreno",
  "char-Hailey_Johnson",
  "char-Rajiv_Patel",
  "char-Tamara_Taylor",
];

/** Distinct list of body texture keys to preload (base + partner bodies). */
export const ALL_CHARACTER_KEYS: string[] = Array.from(
  new Set([
    ...Object.values(AGENT_CUSTOMIZATION).map((c) => c.spriteKey),
    ...Object.values(AGENT_CUSTOMIZATION)
      .map((c) => c.partner?.spriteKey)
      .filter((k): k is string => !!k),
    ...FALLBACK_SPRITES,
  ]),
);

/**
 * Baked palette-swap sheets to preload: texture key → path under
 * assets/characters/. Derived from customKey ("char-custom-{slug}" →
 * "custom/{slug}_custom.png").
 */
export const ALL_CUSTOM_SHEETS: Record<string, string> = Object.fromEntries(
  Object.values(AGENT_CUSTOMIZATION)
    .map((c) => c.customKey)
    .filter((k): k is string => !!k)
    .map((k) => [k, `custom/${k.slice("char-custom-".length)}_custom.png`]),
);

/**
 * Accessory overlay sheets to preload: texture key → path under
 * assets/characters/ ("acc-hijab-Abigail_Chen" →
 * "accessories/hijab-Abigail_Chen.png").
 */
export const ALL_ACCESSORY_SHEETS: Record<string, string> = Object.fromEntries(
  Object.values(AGENT_CUSTOMIZATION)
    .map((c) => c.accessoryKey)
    .filter((k): k is string => !!k)
    .map((k) => [k, `accessories/${k.slice("acc-".length)}.png`]),
);

/**
 * Look up an agent's authored sprite customization, falling back to a stable
 * generic body. The authored table belongs to the NJ-11 presentation; agent
 * ids are not globally namespaced, so another scenario may legitimately
 * reuse one without inheriting NJ-specific clothing, accessories, or couples.
 */
export function resolveAgentSprite(
  agentId: string,
  scenarioId?: string,
): SpriteCustomization {
  const direct = scenarioId === "nj11-2026" ? AGENT_CUSTOMIZATION[agentId] : undefined;
  if (direct) return direct;
  // Stable hash to pick a deterministic fallback (so reloads don't reshuffle).
  let h = 0;
  for (let i = 0; i < agentId.length; i++) h = (h * 31 + agentId.charCodeAt(i)) >>> 0;
  return { spriteKey: FALLBACK_SPRITES[h % FALLBACK_SPRITES.length] };
}
